// Snapshots the generated OpenAPI spec into the Episode 11 pay-skills catalog
// entry.
//
// The catalog wants the spec that describes the ACTUAL API (the one this
// Next.js app serves), not the gateway's minimal auto-synthesized doc. That
// spec is generated by `openapi-gen` into public/openapi.json. This script
// copies it into the catalog provider dir and sets `servers[].url` to the live
// gateway URL, because:
//   - generation runs without a request, so the generated servers[].url is ""
//   - `pay catalog check` warns unless servers[] matches the provider's
//     service_url.
//
// Pricing/payment metadata is intentionally NOT added here: `pay catalog check`
// derives price + payTo + currency by live-probing the gateway (service_url),
// and probe-derived pricing wins over anything inline. So the committed spec
// only needs to be a clean, rich description of the endpoints.
//
// Run from the episode-10 dir:  node scripts/snapshot-catalog-openapi.mjs
// (or `npm run openapi:snapshot`, which regenerates first).

import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const generated = resolve(here, "..", "public", "openapi.json");
const catalogEntry = resolve(
  here,
  "..",
  "..",
  "episode-11-publish",
  "providers",
  "solana-foundation",
  "weather-pro",
  "openapi.json",
);

// Must match `service_url` in the catalog PAY.md frontmatter.
const SERVICE_URL = "https://paysh-video-gateway.vercel.app";

const doc = JSON.parse(readFileSync(generated, "utf8"));
doc.servers = [{ url: SERVICE_URL, description: "Production gateway" }];

writeFileSync(catalogEntry, JSON.stringify(doc, null, 2) + "\n");
console.log(`Snapshotted ${generated}\n            -> ${catalogEntry}`);
console.log(`servers[].url set to ${SERVICE_URL}`);
